import{_ as l,o as n,c as s,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 18 章 公文编制","description":"公文编制不是让 AI “写得像公文”就结束，而是把依据、事项、权限、格式和审核意见组织成一份可以继续流转的材料。本章提供一种可采用的辅助方法，不代表公司现行正式流程。 ::: warning 使用边界 WorkBuddy 可以整理材料、生成初稿、检查格式和形成修改说明…","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 18 章 公文编制/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 18 章 公文编制/index.md","lastUpdated":1784290813000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 18 章 公文编制/index.md"};function t(p,a,r,o,h,d){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-18-章-公文编制" tabindex="-1">第 18 章 公文编制 <a class="header-anchor" href="#第-18-章-公文编制" aria-label="Permalink to &quot;第 18 章 公文编制&quot;">​</a></h1><p>公文编制不是让 AI “写得像公文”就结束，而是把依据、事项、权限、格式和审核意见组织成一份可以继续流转的材料。本章提供一种可采用的辅助方法，不代表公司现行正式流程。</p><div class="warning custom-block"><p class="custom-block-title">使用边界</p><p>WorkBuddy 可以整理材料、生成初稿、检查格式和形成修改说明，但不能代替发文权限、业务审查、合规审查和签发。涉及真实事项时，应使用公司批准的模板与流程。</p></div><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>根据任务说明和参考材料形成请示、报告、通知或纪要初稿。</li><li>把零散意见整理为结构完整的议题材料。</li><li>检查标题、主送单位、正文层次、附件说明和落款是否完整。</li><li>对照审核意见修改正文，并输出修改清单。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>一次合格的辅助编制至少应做到：事实不乱补、依据能定位、事项说清楚、格式可检查、修改可追踪、定稿有人审。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><p>开始前建立一个独立工作目录，并准备：</p><ol><li>任务背景与拟解决的问题。</li><li>经确认的事实、数据和政策依据。</li><li>适用的文种、模板和格式要求。</li><li>需要请示、报告或通知的具体事项。</li><li>审核人、截止时间和交付格式。</li></ol><p>材料不完整时，先列缺口，不要让 AI 根据常识补齐公司事实。</p><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><h3 id="第一步-先做事实与依据清单" tabindex="-1">第一步：先做事实与依据清单 <a class="header-anchor" href="#第一步-先做事实与依据清单" aria-label="Permalink to &quot;第一步：先做事实与依据清单&quot;">​</a></h3><p>让 WorkBuddy 把材料分成“已确认事实、引用依据、待核实内容、缺失材料”。每一项保留来源文件和页码，避免写完后找不到出处。</p><h3 id="第二步-确认文种与写作任务" tabindex="-1">第二步：确认文种与写作任务 <a class="header-anchor" href="#第二步-确认文种与写作任务" aria-label="Permalink to &quot;第二步：确认文种与写作任务&quot;">​</a></h3><p>同一件事用请示、报告或通知表达，目的和语气不同。先写清楚收文对象、预期动作和是否需要审批，再进入正文。</p><h3 id="第三步-先搭结构-再写正文" tabindex="-1">第三步：先搭结构，再写正文 <a class="header-anchor" href="#第三步-先搭结构-再写正文" aria-label="Permalink to &quot;第三步：先搭结构，再写正文&quot;">​</a></h3><p>可以先生成标题和一级结构，人工确认后再扩写。常见结构包括背景与依据、现状或问题、拟办事项、风险与保障、请示事项或工作要求。</p><h3 id="第四步-逐段核对" tabindex="-1">第四步：逐段核对 <a class="header-anchor" href="#第四步-逐段核对" aria-label="Permalink to &quot;第四步：逐段核对&quot;">​</a></h3><p>要求 WorkBuddy 为每个事实句标注来源，为判断句标注“需人工确认”。没有来源的数字、日期、职责和结论必须删除或补证。</p><h3 id="第五步-格式与交付检查" tabindex="-1">第五步：格式与交付检查 <a class="header-anchor" href="#第五步-格式与交付检查" aria-label="Permalink to &quot;第五步：格式与交付检查&quot;">​</a></h3><p>使用批准的模板检查版式，把正文、附件、修改说明和待确认问题分别交付，不覆盖原始文件。</p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>假设需要起草一份《关于开展办公区域节能检查的通知》，输入只有活动时间、检查范围、责任要求和空白模板。WorkBuddy 可以整理通知结构、生成初稿并检查附件说明，但检查范围和责任分工必须由经办人确认。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请在当前工作目录内辅助编制一份公文初稿。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>任务目的：{需要解决的问题}</span></span>
<span class="line"><span>拟用文种：{请示/报告/通知/纪要/待判断}</span></span>
<span class="line"><span>收文对象：{对象}</span></span>
<span class="line"><span>已确认事实：{事实或来源文件}</span></span>
<span class="line"><span>参考依据：{文件名、条款或页码}</span></span>
<span class="line"><span>拟办事项：{需要表达的事项}</span></span>
<span class="line"><span>批准模板：{模板文件；没有则写“未提供”}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请按以下顺序执行：</span></span>
<span class="line"><span>1. 先列事实、依据、缺口和待确认问题，不写正文；</span></span>
<span class="line"><span>2. 判断文种并说明理由；</span></span>
<span class="line"><span>3. 给出正文提纲，等待我确认；</span></span>
<span class="line"><span>4. 依据确认后的提纲生成初稿；</span></span>
<span class="line"><span>5. 对事实、数字、职责、附件和格式做检查；</span></span>
<span class="line"><span>6. 输出初稿、问题清单和修改说明。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不得虚构公司流程、部门职责、政策依据和数据，不得覆盖原文件。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>文种、主送对象和行文目的是否正确。</li><li>事实、数字、名称、日期和引用依据是否准确。</li><li>拟办事项是否完整，是否超出经办人权限。</li><li>会签、审批、签发和外发是否由有权限人员完成。</li><li>生成文件是否使用批准模板并保留可追踪版本。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>公文初稿：结构完整，语言清楚，不含无来源事实。</li><li>依据清单：每项关键事实可以回到原材料。</li><li>待确认问题：未解决事项单独列出，没有藏在正文中。</li><li>修改说明：说明改了什么、为什么改、还需谁确认。</li><li>格式检查表：标题、层次、附件、落款和页码等项目已核对。</li></ul><h2 id="常见弯路" tabindex="-1">常见弯路 <a class="header-anchor" href="#常见弯路" aria-label="Permalink to &quot;常见弯路&quot;">​</a></h2><ul><li><strong>直接让 AI 写终稿</strong>：输入缺口会被流畅文字掩盖。先做事实清单和提纲。</li><li><strong>只检查语句，不检查权限</strong>：文字通顺不等于可以发出。签发和外发必须走正式流程。</li><li><strong>反复覆盖同一个文件</strong>：审核意见难追踪。保留原件、初稿、审核稿和定稿的版本关系。</li></ul><h2 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h2><ul><li>不向未批准的外部服务上传敏感材料。</li><li>不把印章、签名、个人信息和密钥交给自动化流程处理。</li><li>不自动发送、盖章、提交审批或替代投资与合规判断。</li><li>不把合成示例当作正式模板或公司现行制度。</li></ul><h2 id="可复用资产" tabindex="-1">可复用资产 <a class="header-anchor" href="#可复用资产" aria-label="Permalink to &quot;可复用资产&quot;">​</a></h2><ul><li>公文任务卡。</li><li>事实与依据清单。</li><li>公文结构模板。</li><li>格式检查表。</li><li>审核意见与修改说明模板。</li></ul>`,36)])])}const b=l(e,[["render",t]]);export{u as __pageData,b as default};
